import React, { useState,useEffect, useRef } from "react";
import { Container,Modal, Button, Form, Card, Alert } from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";
import "./home2.css"; // Import custom styles

function SpellingGame() {
  const [wordsIKindaKnow, setWordsIKindaKnow] = useState(["apple", "banana", "cat", "dog"]);
  const [wordsIDontKnow, setWordsIDontKnow] = useState(["anaconda", "table", "cable"]);
  const [levelWords, setLevelWords] = useState(["cane", "strawberry", "cage"]);
  const [wordsIKnow, setWordsIKnow] = useState([]);
  const [currentWord, setCurrentWord] = useState("");
  const [userInput, setUserInput] = useState("");
  const [message, setMessage] = useState("");
  const [incorrectAttempts, setIncorrectAttempts] = useState(0);
  const [gameLost, setGameLost] = useState(false);
  const [gameWon, setGameWon] = useState(false);
  const [isSpeakingDisabled, setIsSpeakingDisabled] = useState(false);
  const [showAlert, setShowAlert] = useState(false); // Track incorrect answer alert
  const [showCorrect, setShowCorrect] = useState(false);
  const [hintClicks, setHintClicks] = useState(0); // Track the number of hint clicks
  const [hint, setHint] = useState(""); // Store hint
  const [showModal, setShowModal] = useState(false);




  const inputRef = useRef(null);

    // Check for game win condition
    if (
      wordsIKindaKnow.length === 0 &&
      wordsIDontKnow.length === 0 &&
      levelWords.length === 0
    ) {
      setGameWon(true);
      setMessage("🎉 You won the game!");
    }
    
    // Check for game win condition
    useEffect(() => {
      if (
        wordsIKindaKnow.length === 0 &&
        wordsIDontKnow.length === 0 &&
        levelWords.length === 0
      ) {
        setGameWon(true);
        setMessage("🎉 You won the game!");
      }
    }, [wordsIKindaKnow, wordsIDontKnow, levelWords]);

  

  const startGame = () => {
    setWordsIKnow([]);
    setIncorrectAttempts(0);
    setGameLost(false);
    setGameWon(false);
    setShowAlert(false);
    setHintClicks(0); // Reset hint clicks

    // Determine which list to get the current word from
    if (wordsIDontKnow.length > 0) {
      setCurrentWord(wordsIDontKnow[0]);
      speakWord(wordsIDontKnow[0]);
    } else if (wordsIKindaKnow.length > 0) {
      setCurrentWord(wordsIKindaKnow[0]);
      speakWord(wordsIKindaKnow[0]);
    } else if (levelWords.length > 0) {
      setCurrentWord(levelWords[0]);
      speakWord(levelWords[0]);
    } else {
      setGameWon(true);
    }

    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
      }
    }, 100);
  };

  const speakWord = (word) => {
    if (word) {
      console.log("Speaking word:", word);
      const synth = window.speechSynthesis;
      const utterance = new SpeechSynthesisUtterance(word);
      utterance.lang = "en-ZA";
      utterance.rate = 0.9;
      utterance.pitch = 1.0;
      utterance.volume = 1.0;

      setIsSpeakingDisabled(true);
      setTimeout(() => setIsSpeakingDisabled(false), 2000);

      setTimeout(() => {
        synth.speak(utterance);
      }, 100);
    } else {
      console.log("No word to speak.");
    }
  };

  const checkSpelling = () => {
    if (userInput.toLowerCase() === currentWord.toLowerCase()) {
      setMessage("✅ Correct! Well done!");
      setShowCorrect(true);
      setTimeout(() => setShowCorrect(false), 2000);
  
      setWordsIKnow((prev) => [...prev, currentWord]); // Move to wordsIKnow
  
      // Calculate the next word before updating state
      let updatedWordsIDontKnow = wordsIDontKnow.filter(word => word !== currentWord);
      let updatedWordsIKindaKnow = wordsIKindaKnow.filter(word => word !== currentWord);
      let updatedLevelWords = levelWords.filter(word => word !== currentWord);
  
      let nextWord = updatedWordsIDontKnow[0] || updatedWordsIKindaKnow[0] || updatedLevelWords[0] || null;
  
      // Update the state with new word lists
      setWordsIDontKnow(updatedWordsIDontKnow);
      setWordsIKindaKnow(updatedWordsIKindaKnow);
      setLevelWords(updatedLevelWords);
  
      // Move to the next word if available, otherwise end the game
      if (nextWord) {
        setCurrentWord(nextWord);
        speakWord(nextWord); // Speak the new word
      } else {
        setGameWon(true); // No words left
      }
  
      setUserInput(""); // Reset input
      setHintClicks(0);
      setHint("");
    } else {
      setIncorrectAttempts(prev => prev + 1);
      setMessage("❌ Incorrect! Try again.");
      setShowAlert(true);
      setTimeout(() => setShowAlert(false), 2000);
  
      if (incorrectAttempts + 1 === 2) {
        setMessage("❌ Incorrect! Moving to the next word.");
        moveToNextWord();
      }
    }
  };
  
  
  
  const moveToNextWord = () => {
    let nextWord;
    if (wordsIDontKnow.length > 0) {
      nextWord = wordsIDontKnow[0];
    } else if (wordsIKindaKnow.length > 0) {
      nextWord = wordsIKindaKnow[0];
    } else if (levelWords.length > 0) {
      nextWord = levelWords[0];
    } else {
      setGameWon(true);
      return; // If there are no more words, end the game
    }

    setCurrentWord(nextWord);
    setUserInput("");
    setHintClicks(0); // Reset hint clicks when moving to next word
    setHint("");
    speakWord(nextWord); // Speak the new word
  };

  const getHint = () => {
    let hint = currentWord.split("").map((char) => "_").join("");
    if (hintClicks === 0) {
      hint = currentWord[0] + hint.slice(1); // First letter revealed
    } else if (hintClicks === 1) {
      hint = hint.slice(0, -1) + currentWord[currentWord.length - 1]; // Last letter revealed
    } else if (hintClicks === 2) {
      hint = currentWord[0] + hint.slice(1, -1) + currentWord[currentWord.length - 1]; // Second letter revealed
    } else if (hintClicks === 3) {
      hint = currentWord[0] + currentWord[1] + hint.slice(2, -2) + currentWord[currentWord.length - 2] + currentWord[currentWord.length - 1]; // Second last letter revealed
    }
    return hint;
  };

  const handleHintClick = () => {
    if (hintClicks < 4) {
      setHintClicks(hintClicks + 1);
      setHint(getHint());
    }
  };

  const speakPhonetically = (text) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'en-US'; // Set language to English (adjust if needed)
    utterance.rate = 0.1; // Adjust speed (0.5 is slower, 1 is normal, 2 is fast)
    speechSynthesis.speak(utterance);
  };

  const revealWord = async () => {
    speakPhonetically(currentWord);
    setMessage(`✅ The word is: ${currentWord}`);
    setShowModal(true);
  
    let updatedWordsIKindaKnow = wordsIKindaKnow.filter(word => word !== currentWord);
    let updatedLevelWords = levelWords.filter(word => word !== currentWord);
    let updatedWordsIDontKnow = [...wordsIDontKnow, currentWord];
  
    setWordsIKindaKnow(updatedWordsIKindaKnow);
    setLevelWords(updatedLevelWords);
    setWordsIDontKnow(updatedWordsIDontKnow);
  
    setTimeout(() => {
      let nextWord = updatedWordsIDontKnow.find(word => word !== currentWord) || updatedWordsIKindaKnow[0] || updatedLevelWords[0] || null;
  
      if (nextWord) {
        setCurrentWord(nextWord);
        speakWord(nextWord);
      } else {
        setGameWon(true);
      }
  
      setUserInput("");
      setHintClicks(0);
    }, 100); 
  };
  



  return (
    <Container className="text-center mt-5">
      <Card className="p-4">
        <h1>Spelling Game</h1>
        
        {showAlert && (
          <Alert variant="danger" className="shake">
            ❌ Oops! That's incorrect. Try again! 🧐
          </Alert>
        )}
        {showCorrect && (
          <Alert variant="success" className="shake">
          ✅ Hooray!!,You got it correct 😀
          </Alert>
        )}
        <Modal show={showModal} onHide={() => setShowModal(false)} centered>
           <Modal.Header closeButton>
              <Modal.Title className="text-success">🎉 Word Revealed! 🎉</Modal.Title>
          </Modal.Header>
            <Modal.Body>
              <h2 className="text-center text-primary">✅ The word is: {currentWord}</h2>
            </Modal.Body>
            <Modal.Footer>
              <Button variant="secondary" onClick={() => setShowModal(false)}>
                Close
              </Button>
            </Modal.Footer>
        </Modal>


        {gameWon ? (
          <h2>🎉 Congratulations! You've won the game! 🎉</h2>
        ) : gameLost ? (
          <>
            <h2>😔 You've Lost! 😔</h2>
            <p>You got six incorrect attempts on a word.</p>
            <Button onClick={startGame} variant="primary">Restart Game</Button>
          </>
        ) : currentWord === "" ? (
          <Button onClick={startGame} variant="primary">Start Game</Button>
        ) : (
          <>
            <h2>Listen carefully to the word and spell it:</h2>
            <Button 
              onClick={() => speakWord(currentWord)} 
              variant="info" 
              className="mb-3"
              disabled={isSpeakingDisabled}
            >
              🔊 Repeat Word {isSpeakingDisabled ? " (Wait...)" : ""}
            </Button>
            
            <div className="hint-section">
              <h4>Your Hint:</h4>
              <Form.Label className="hint-label">{hint}</Form.Label>
            </div>

            <Button 
              onClick={handleHintClick} 
              variant="warning" 
              className="mt-2"
              disabled={hintClicks >= 4}
            >
              Get Hint
            </Button>

            {hintClicks === 4 && (
              <Button 
                onClick={revealWord} 
                variant="success" 
                className="mt-2"
              >
                Reveal Word
              </Button>
            )}

            <Form.Control
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              className="mb-3"
              ref={inputRef}
            />
            <Button variant="success" onClick={checkSpelling}>Submit</Button>
            <p className="mt-3">{message}</p>
            <p>Incorrect Attempts: {incorrectAttempts} / 6</p>
          </>
        )}
      </Card>
    </Container>
  );
}

export default SpellingGame;
